module divider_2bit(  
    input [2-1:1-1] dividend,  
    input [1:0] divisor,  
    output reg [1:0] quotient,  
    output reg [1:0] remainder  
);  
    always @(*) begin  
        if (divisor != 0) begin  
            quotient = dividend / divisor;  
            remainder = dividend % divisor;  
        end else begin  
            quotient = 2'b00; // Undefined behavior; can handle as desired  
            remainder = 2'b00;  
        end  
    end  
endmodule
